#include <threads.h>
#include <hardware.h>
#include <terminals.h>
#include <string.h>

/*
 * COMP 421 Lab 1 - MonTTY Terminal Device Driver
 *
 * Mesa-style monitor for terminal device driver.
 * All 7 entry procedures of the monitor are implemented below.
 *
 * Section 6.1: ReceiveInterrupt, TransmitInterrupt
 * Section 6.2: WriteTerminal, ReadTerminal, InitTerminal,
 *              TerminalDriverStatistics, InitTerminalDriver
 */

/* Per-terminal state */
struct term_state {
    int initialized;                    /* Whether terminal is initialized */
    char input_buf[TERMINAL_MAX_LINE];  /* Line-oriented input buffer */
    int input_len;                      /* Current input length */

    char echo_buf[TERMINAL_MAX_LINE];   /* Pending echo characters */
    int echo_len;                       /* Number of pending echo chars */
    int echo_pos;                       /* Current position in echo_buf */

    char *write_buf;                    /* Current WriteTerminal buffer */
    int write_len;                      /* Remaining chars in write_buf */
    int write_total;                    /* Total chars to write */

    int hw_busy;                        /* Hardware is busy transmitting */

    struct termstat stats;              /* Statistics for this terminal */
};

/* Global driver state */
static int driver_initialized = 0;
static struct term_state terminals[NUM_TERMINALS];
static cond_id_t read_conds[NUM_TERMINALS];  /* Readers wait on line completion */
static cond_id_t write_cond;                 /* Writers wait on hw ready */

/* Forward declarations of internal procedures */
static void send_next_output(int term);
static void output_char(int term, char c);

/*
 * InitTerminalDriver() - Entry procedure
 * Initialize the terminal driver (once only)
 */
int
InitTerminalDriver(void)
{
    Declare_Monitor_Entry_Procedure();

    int i;

    if (driver_initialized) {
        return -1;  /* Already initialized */
    }

    driver_initialized = 1;

    /* Initialize all terminal states */
    for (i = 0; i < NUM_TERMINALS; i++) {
        terminals[i].initialized = 0;
        terminals[i].input_len = 0;
        terminals[i].echo_len = 0;
        terminals[i].echo_pos = 0;
        terminals[i].write_buf = NULL;
        terminals[i].write_len = 0;
        terminals[i].hw_busy = 0;

        /* Stats start at -1 for uninitialized terminals */
        terminals[i].stats.tty_in = -1;
        terminals[i].stats.tty_out = -1;
        terminals[i].stats.user_in = -1;
        terminals[i].stats.user_out = -1;

        /* Create condition variables for readers */
        read_conds[i] = CondCreate();
    }

    /* Create condition variable for writers */
    write_cond = CondCreate();

    return 0;
}

/*
 * InitTerminal() - Entry procedure
 * Initialize a specific terminal
 */
int
InitTerminal(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized) {
        return -1;  /* Driver not initialized */
    }

    if (term < 0 || term >= NUM_TERMINALS) {
        return -1;  /* Invalid terminal number */
    }

    if (terminals[term].initialized) {
        return -1;  /* Already initialized */
    }

    if (InitHardware(term) == -1) {
        return -1;  /* Hardware initialization failed */
    }

    /* Initialize terminal state */
    terminals[term].initialized = 1;
    terminals[term].input_len = 0;
    terminals[term].echo_len = 0;
    terminals[term].echo_pos = 0;
    terminals[term].write_buf = NULL;
    terminals[term].write_len = 0;
    terminals[term].hw_busy = 0;

    /* Reset statistics to 0 */
    terminals[term].stats.tty_in = 0;
    terminals[term].stats.tty_out = 0;
    terminals[term].stats.user_in = 0;
    terminals[term].stats.user_out = 0;

    return 0;
}

/*
 * WriteTerminal() - Entry procedure
 * Write buflen characters from buf to terminal
 */
int
WriteTerminal(int term, char *buf, int buflen)
{
    Declare_Monitor_Entry_Procedure();

    int i;

    if (!driver_initialized) {
        return -1;
    }

    if (term < 0 || term >= NUM_TERMINALS) {
        return -1;
    }

    if (!terminals[term].initialized) {
        return -1;
    }

    if (buf == NULL) {
        return -1;
    }

    if (buflen < 0) {
        return -1;
    }

    if (buflen == 0) {
        return 0;
    }

    /* Track user input */
    terminals[term].stats.user_in += buflen;

    /* Write characters one at a time */
    for (i = 0; i < buflen; i++) {
        /* Wait for hardware to be ready */
        while (terminals[term].hw_busy) {
            CondWait(write_cond);
        }

        /* Send the character (with output processing for \n) */
        if (buf[i] == '\n') {
            /* Output \n as \r\n */
            output_char(term, '\r');
            while (terminals[term].hw_busy) {
                CondWait(write_cond);
            }
            output_char(term, '\n');
        } else {
            output_char(term, buf[i]);
        }
    }

    return buflen;
}

/*
 * ReadTerminal() - Entry procedure
 * Read a line of input from terminal
 */
int
ReadTerminal(int term, char *buf, int buflen)
{
    Declare_Monitor_Entry_Procedure();

    int chars_read;
    int i;

    if (!driver_initialized) {
        return -1;
    }

    if (term < 0 || term >= NUM_TERMINALS) {
        return -1;
    }

    if (!terminals[term].initialized) {
        return -1;
    }

    if (buf == NULL && buflen > 0) {
        return -1;
    }

    if (buflen < 0) {
        return -1;
    }

    if (buflen == 0) {
        return 0;
    }

    /* Wait for a complete line (containing \n) */
    while (1) {
        /* Check if we have a complete line in input buffer */
        int has_newline = 0;
        for (i = 0; i < terminals[term].input_len; i++) {
            if (terminals[term].input_buf[i] == '\n') {
                has_newline = 1;
                break;
            }
        }

        if (has_newline) {
            break;  /* We have a complete line */
        }

        /* No complete line yet, wait for more input */
        CondWait(read_conds[term]);
    }

    /* Copy line data to user buffer */
    chars_read = 0;
    while (chars_read < buflen && terminals[term].input_len > 0) {
        buf[chars_read] = terminals[term].input_buf[0];

        /* Remove from input buffer */
        int j;
        for (j = 0; j < terminals[term].input_len - 1; j++) {
            terminals[term].input_buf[j] = terminals[term].input_buf[j + 1];
        }
        terminals[term].input_len--;
        chars_read++;

        /* Stop at newline */
        if (buf[chars_read - 1] == '\n') {
            break;
        }
    }

    /* Track user output */
    terminals[term].stats.user_out += chars_read;

    return chars_read;
}

/*
 * TerminalDriverStatistics() - Entry procedure
 * Return statistics snapshot for all terminals
 */
int
TerminalDriverStatistics(struct termstat *stats)
{
    Declare_Monitor_Entry_Procedure();

    int i;

    if (!driver_initialized) {
        return -1;
    }

    if (stats == NULL) {
        return -1;
    }

    /* Copy statistics for all terminals */
    for (i = 0; i < NUM_TERMINALS; i++) {
        if (terminals[i].initialized) {
            stats[i] = terminals[i].stats;
        } else {
            stats[i].tty_in = -1;
            stats[i].tty_out = -1;
            stats[i].user_in = -1;
            stats[i].user_out = -1;
        }
    }

    return 0;
}

/*
 * ReceiveInterrupt() - Entry procedure
 * Handle character received from keyboard (cannot block)
 */
void
ReceiveInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();

    char c;

    if (term < 0 || term >= NUM_TERMINALS || !terminals[term].initialized) {
        return;
    }

    /* Read character from hardware */
    c = ReadDataRegister(term);
    terminals[term].stats.tty_in++;

    /* Process and store character in input buffer */
    if (c == '\r' || c == '\n') {
        /* Store as newline, echo as \r\n */
        if (terminals[term].input_len < TERMINAL_MAX_LINE) {
            terminals[term].input_buf[terminals[term].input_len++] = '\n';

            /* Add to echo queue */
            if (terminals[term].echo_len < TERMINAL_MAX_LINE - 1) {
                terminals[term].echo_buf[terminals[term].echo_len++] = '\r';
                terminals[term].echo_buf[terminals[term].echo_len++] = '\n';
            }

            /* Signal waiting readers - we have a complete line */
            CondSignal(read_conds[term]);
        }
    } else if (c == '\b' || c == '\177') {
        /* Backspace or delete */
        if (terminals[term].input_len > 0) {
            terminals[term].input_len--;

            /* Add backspace echo sequence to queue: \b \space \b */
            if (terminals[term].echo_len < TERMINAL_MAX_LINE - 2) {
                terminals[term].echo_buf[terminals[term].echo_len++] = '\b';
                terminals[term].echo_buf[terminals[term].echo_len++] = ' ';
                terminals[term].echo_buf[terminals[term].echo_len++] = '\b';
            }
        }
        /* If buffer empty, no echo - just silently ignore or optionally bell */
    } else {
        /* Regular character */
        if (terminals[term].input_len < TERMINAL_MAX_LINE) {
            terminals[term].input_buf[terminals[term].input_len++] = c;
            terminals[term].echo_buf[terminals[term].echo_len++] = c;
        } else {
            /* Buffer full - drop the character, optionally ring bell */
            /* (no echo for dropped character) */
        }
    }

    /* Try to send pending echo if hardware is ready */
    send_next_output(term);
}

/*
 * TransmitInterrupt() - Entry procedure
 * Handle character transmission completion
 */
void
TransmitInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (term < 0 || term >= NUM_TERMINALS || !terminals[term].initialized) {
        return;
    }

    /* Hardware is now ready for next character */
    terminals[term].hw_busy = 0;

    /* Send next output (echo has priority) */
    send_next_output(term);

    /* Signal any waiting writers that hardware is ready */
    CondSignal(write_cond);
}

/*
 * send_next_output() - Internal procedure
 * Try to send the next character (echo has priority over WriteTerminal)
 * This is called from ReceiveInterrupt and TransmitInterrupt
 * MUST NOT BLOCK - called from ReceiveInterrupt which cannot block
 */
static void
send_next_output(int term)
{
    /* Sanity check */
    if (term < 0 || term >= NUM_TERMINALS || !terminals[term].initialized) {
        return;
    }

    /* If hardware is busy, nothing to do */
    if (terminals[term].hw_busy) {
        return;
    }

    /* Echo has priority over WriteTerminal */
    if (terminals[term].echo_len > 0) {
        char c = terminals[term].echo_buf[terminals[term].echo_pos++];
        WriteDataRegister(term, c);
        terminals[term].stats.tty_out++;
        terminals[term].hw_busy = 1;

        /* Check if we've sent all echo chars */
        if (terminals[term].echo_pos >= terminals[term].echo_len) {
            terminals[term].echo_len = 0;
            terminals[term].echo_pos = 0;
        }
    } else if (terminals[term].write_buf != NULL && terminals[term].write_len > 0) {
        /* Send next character from WriteTerminal */
        char c = terminals[term].write_buf[terminals[term].write_total - terminals[term].write_len];
        WriteDataRegister(term, c);
        terminals[term].stats.tty_out++;
        terminals[term].write_len--;
        terminals[term].hw_busy = 1;
    }
}

