        /* If buffer full, drop the character silently */
    }

    /* Try to send pending echo if hardware is ready */
    send_next_output(term);
}

/*
 * TransmitInterrupt() - Entry procedure
 * Handle character transmission completion
 */
void
TransmitInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (term < 0 || term >= NUM_TERMINALS || !terminals[term].initialized) {
        return;
    }

    /* Hardware is now ready for next character */
    terminals[term].hw_busy = 0;

    /* Send next output (echo has priority) */
    send_next_output(term);

    /* Signal any waiting writers that hardware is ready */
    CondSignal(write_cond);
}

/*
 * send_next_output() - Internal procedure
 * Try to send the next character (echo has priority over WriteTerminal)
 * This is called from ReceiveInterrupt and TransmitInterrupt
 * MUST NOT BLOCK - called from ReceiveInterrupt which cannot block
 */
static void
send_next_output(int term)
{
    /* Sanity check */
    if (term < 0 || term >= NUM_TERMINALS || !terminals[term].initialized) {
        return;
    }

    /* If hardware is busy, nothing to do */
    if (terminals[term].hw_busy) {
        return;
    }

    /* Echo has priority over WriteTerminal */
    if (terminals[term].echo_len > 0) {
        char c = terminals[term].echo_buf[terminals[term].echo_pos++];
        WriteDataRegister(term, c);
        terminals[term].stats.tty_out++;
        terminals[term].hw_busy = 1;

        /* Check if we've sent all echo chars */
        if (terminals[term].echo_pos >= terminals[term].echo_len) {
            terminals[term].echo_len = 0;
            terminals[term].echo_pos = 0;
        }
    }
}

